  'Adding sensory details (smell, sound, texture) to Memory Palace images strengthens recall.': { prompt: 'Agregar detalles sensoriales (olor, sonido, textura) a las imágenes del Palacio de la Memoria fortalece el recuerdo.', options: ['Verdadero', 'Falso'], correctAnswer: 'Verdadero' },
