  'Why does the Memory Palace technique work?': { prompt: '¿Por qué funciona la técnica del Palacio de la Memoria?', options: ['Usa la repetición mecánica', 'Aprovecha la memoria espacial natural y los sistemas de procesamiento visual del cerebro', 'Es un tipo de hipnosis', 'Requiere equipo especial de entrenamiento cerebral'], correctAnswer: 'Aprovecha la memoria espacial natural y los sistemas de procesamiento visual del cerebro' },
  'The Memory Palace technique can be learned by anyone, not just people with "good memory."': { prompt: 'La técnica del Palacio de la Memoria puede ser aprendida por cualquiera, no solo por personas con "buena memoria".', options: ['Verdadero', 'Falso'], correctAnswer: 'Verdadero' },
  'What is a "journey method"?': { prompt: '¿Qué es el "método del viaje"?', options: ['Planificación de viajes', 'Una variación del Palacio de la Memoria usando una ruta con paradas ordenadas', 'Un programa de fitness', 'Una técnica de lectura'], correctAnswer: 'Una variación del Palacio de la Memoria usando una ruta con paradas ordenadas' },
  'What is spaced repetition?': { prompt: '¿Qué es la repetición espaciada?', options: ['Repetir algo lo más rápido posible', 'Revisar información a intervalos crecientes para optimizar la retención', 'Espaciar las sesiones de estudio al azar', 'Repetir el mismo ejercicio'], correctAnswer: 'Revisar información a intervalos crecientes para optimizar la retención' },
  'Anki is a popular spaced repetition flashcard app.': { prompt: 'Anki es una aplicación popular de flashcards con repetición espaciada.', options: ['Verdadero', 'Falso'], correctAnswer: 'Verdadero' },
